import { useState } from "react";

function App() {
  const [resumeText, setResumeText] = useState("");
  const [result, setResult] = useState("");

  const analyzeResume = () => {
    if (resumeText.trim() === "") {
      setResult("Please paste your resume content first.");
    } else {
      setResult(
          "Resume analyzed successfully. Skills, strengths, and improvement areas will appear here."
      );
    }
  };

  return (
      <div
          style={{
            minHeight: "100vh",
            backgroundColor: "#f4f7fb",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            fontFamily: "Arial, sans-serif",
          }}
      >
        <div
            style={{
              backgroundColor: "white",
              padding: "30px",
              borderRadius: "12px",
              boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
              width: "500px",
              textAlign: "center",
            }}
        >
          <h1>AI Resume Analyzer 🚀</h1>
          <p>Paste your resume below and get instant feedback.</p>

          <textarea
              placeholder="Paste your resume content here..."
              value={resumeText}
              onChange={(e) => setResumeText(e.target.value)}
              style={{
                width: "100%",
                height: "180px",
                padding: "12px",
                marginTop: "10px",
                borderRadius: "8px",
                border: "1px solid #ccc",
                resize: "none",
                fontSize: "14px",
              }}
          />

          <br /><br />

          <button
              onClick={analyzeResume}
              style={{
                backgroundColor: "#007bff",
                color: "white",
                border: "none",
                padding: "12px 20px",
                borderRadius: "8px",
                cursor: "pointer",
                fontSize: "16px",
              }}
          >
            Analyze Resume
          </button>

          <h3 style={{ marginTop: "25px" }}>Result:</h3>
          <p>{result}</p>
        </div>
      </div>
  );
}

export default App;
